**iOS Example:**

**Step 1: Add Frameworks**

In your `Podfile`, add the following frameworks:

```ruby
pod 'GoogleMaps'
pod 'Google-Maps-iOS-Utils'
```

**Step 2: Request Location Permissions**

In your `ViewController.swift` file, request location permissions:

```swift
import UIKit
import CoreLocation
import GoogleMaps

class ViewController: UIViewController, CLLocationManagerDelegate {

    let locationManager = CLLocationManager()

    override func viewDidLoad() {
        super.viewDidLoad()
        locationManager.requestWhenInUseAuthorization()
    }

    @IBAction func startButtonTapped(_ sender: UIButton) {
        startTracking()
    }

    private func startTracking() {
        if CLLocationManager.locationServicesEnabled() {
            locationManager.startUpdatingLocation()
        } else {
            print("Location services are not enabled")
        }
    }

    func locationManager(_ manager: CLLocationManager, didUpdateLocations locations: [CLLocation]) {
        guard let location = locations.last else { return }
        let latLng = CLLocationCoordinate2D(latitude: location.coordinate.latitude, longitude: location.coordinate.longitude)
        let camera = GMSCameraPosition.camera(withLatitude: latLng.latitude, longitude: latLng.longitude, zoom: 15)
        let mapView = GMSMapView.map(withFrame: CGRect.zero, camera: camera)
        mapView.isMyLocationEnabled = true
        mapView.animate(to: camera)
        mapView.addMarker(GMSMarker(position: latLng))
        view.addSubview(mapView)
    }
}
```

**Step 3: Display Route on Map**

In your `ViewController.swift` file, display the route on the map:

```swift
private func displayRoute(route: [CLLocation]) {
    let polyline = GMSPolyline(path: route.map { CLLocationCoordinate2D(latitude: $0.coordinate.latitude, longitude: $0.coordinate.longitude) })
    polyline.strokeColor = UIColor.red
    polyline.strokeWidth = 10
    polyline.map = mapView
}
```

